@namespace Lumeo
@implements IAsyncDisposable
@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (EffectiveOpen && !_minimized && !_maximized)
{
    <div id="@_windowId"
         class="@CssClass"
         style="@StyleString"
         role="dialog"
         aria-modal="false"
         aria-labelledby="@_titleId"
         tabindex="-1"
         @onpointerdown="BringToFront"
         @onkeydown="HandleKeyDown"
         @attributes="AdditionalAttributes">
        @* Title bar *@
        <div id="@_titleBarId"
             class="flex items-center gap-2 px-4 py-2 border-b border-border/40 bg-card rounded-t-lg cursor-default select-none"
             @onpointerdown="HandleTitleBarPointerDown"
             @onpointermove="HandlePointerMove"
             @onpointerup="HandlePointerUp"
             @onpointercancel="HandlePointerUp">
            <span id="@_titleId" class="flex-1 text-sm font-medium text-foreground truncate">
                @if (TitleContent is not null)
                {
                    @TitleContent
                }
                else
                {
                    @Title
                }
            </span>
            @* stopPropagation: a pointerdown on the control buttons must not start
               a drag — and must not capture the pointer on the title bar, which
               would retarget the subsequent click away from the button. *@
            <div class="flex items-center gap-1" @onpointerdown:stopPropagation="true">
                @if (ShowMinimize)
                {
                    <button type="button"
                            class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            @onclick="ToggleMinimize"
                            aria-label="@L["Window.Minimize"]">
                        <SvgGlyph Svg="@(LumeoIcons.Minus)" class="h-3 w-3" />
                    </button>
                }
                @if (ShowMaximize)
                {
                    <button type="button"
                            class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            @onclick="ToggleMaximize"
                            aria-label="@L["Window.Maximize"]">
                        <SvgGlyph Svg="@(LumeoIcons.Square)" class="h-3 w-3" />
                    </button>
                }
                @if (ShowClose)
                {
                    <button type="button"
                            class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            @onclick="Close"
                            aria-label="@L["Window.Close"]">
                        <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
                    </button>
                }
            </div>
        </div>

        @* Body *@
        <div class="overflow-auto p-4 flex-1">
            @ChildContent
        </div>

        @* Footer *@
        @if (FooterContent is not null)
        {
            <div class="px-4 py-3 border-t border-border/40 bg-card rounded-b-lg">
                @FooterContent
            </div>
        }

        @* Resize handle *@
        @if (Resizable)
        {
            @* Touch hit target is 44×44 per WCAG 2.5.5; on desktop (sm and up)
               the handle compresses to a 16×16 corner so it doesn't intrude on
               the window's content area. Inner SVG stays a fixed 16×16 visual
               regardless of hit-area size so the chevron glyph doesn't scale. *@
            @* Physical `right-0` (not logical `end-0`): the resize math (_dragStartPosX + dx, the
               max-width clamp) and the `cursor-se-resize` glyph are physical southeast, so the handle must
               stay on the physical bottom-right in RTL too — otherwise it jumps to the bottom-left while
               dragging it outward shrinks/stalls the window (Codex P2). *@
            <div id="@_resizeHandleId"
                 role="button"
                 aria-label="@L["Window.Resize"]"
                 class="absolute bottom-0 right-0 flex items-end justify-end w-11 h-11 sm:w-4 sm:h-4 cursor-se-resize opacity-40 hover:opacity-80"
                 @onpointerdown="HandleResizePointerDown"
                 @onpointermove="HandlePointerMove"
                 @onpointerup="HandlePointerUp"
                 @onpointercancel="HandlePointerUp">
                <svg viewBox="0 0 10 10" class="w-4 h-4 text-muted-foreground fill-current" aria-hidden="true">
                    <path d="M0 10L10 0M4 10L10 4M8 10L10 8" stroke="currentColor" stroke-width="1" fill="none"/>
                </svg>
            </div>
        }
    </div>
}
else if (EffectiveOpen && _minimized)
{
    @* Minimized title bar only *@
    <div id="@_windowId"
         class="fixed flex items-center gap-2 px-4 py-2 bg-card border border-border/40 rounded-lg shadow-md"
         style="@MinimizedStyleString"
         role="dialog"
         aria-modal="false"
         aria-labelledby="@_titleId"
         tabindex="-1"
         @onpointerdown="BringToFront"
         @onkeydown="HandleKeyDown"
         @attributes="AdditionalAttributes">
        <span id="@_titleId" class="flex-1 text-sm font-medium text-foreground truncate max-w-[200px]">@Title</span>
        <button type="button"
                class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                @onclick="ToggleMinimize"
                aria-label="@L["Window.Restore"]">
            <SvgGlyph Svg="@(LumeoIcons.Square)" class="h-3 w-3" />
        </button>
        @if (ShowClose)
        {
            <button type="button"
                    class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                    @onclick="Close"
                    aria-label="@L["Window.Close"]">
                <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
            </button>
        }
    </div>
}
else if (EffectiveOpen && _maximized)
{
    @* Maximized — fills most of viewport *@
    <div id="@_windowId"
         class="fixed inset-4 flex flex-col bg-card border border-border/40 rounded-lg shadow-xl overflow-hidden"
         style="@ZStyle"
         role="dialog"
         aria-modal="false"
         aria-labelledby="@_titleId"
         tabindex="-1"
         @onpointerdown="BringToFront"
         @onkeydown="HandleKeyDown"
         @attributes="AdditionalAttributes">
        <div class="flex items-center gap-2 px-4 py-2 border-b border-border/40 bg-card select-none">
            <span id="@_titleId" class="flex-1 text-sm font-medium text-foreground truncate">@Title</span>
            <div class="flex items-center gap-1">
                @if (ShowMinimize)
                {
                    <button type="button"
                            class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            @onclick="ToggleMinimize"
                            aria-label="@L["Window.Minimize"]">
                        <SvgGlyph Svg="@(LumeoIcons.Minus)" class="h-3 w-3" />
                    </button>
                }
                <button type="button"
                        class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                        @onclick="ToggleMaximize"
                        aria-label="@L["Window.Restore"]">
                    <SvgGlyph Svg="@(LumeoIcons.Minimize2)" class="h-3 w-3" />
                </button>
                @if (ShowClose)
                {
                    <button type="button"
                            class="flex h-11 w-11 sm:h-7 sm:w-7 items-center justify-center rounded-sm text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            @onclick="Close"
                            aria-label="@L["Window.Close"]">
                        <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
                    </button>
                }
            </div>
        </div>
        <div class="overflow-auto p-4 flex-1">
            @ChildContent
        </div>
        @if (FooterContent is not null)
        {
            <div class="px-4 py-3 border-t border-border/40 bg-card">
                @FooterContent
            </div>
        }
    </div>
}

@code {
    /// <summary>Whether the window is visible. Pair with <see cref="OpenChanged"/> for two-way binding; leave unbound for uncontrolled use (Escape/close-button clicks self-manage visibility).</summary>
    [Parameter] public bool Open { get; set; }

    /// <summary>Raised when the window is closed (Escape, close button) or reopened.</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>Plain-text title shown in the title bar. Ignored when <see cref="TitleContent"/> is set.</summary>
    [Parameter] public string Title { get; set; } = "";

    /// <summary>Custom title bar content, overriding <see cref="Title"/>. Not shown in the minimized/maximized title bars, which always render plain <see cref="Title"/>.</summary>
    [Parameter] public RenderFragment? TitleContent { get; set; }

    /// <summary>The window's body content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Optional content rendered in a bordered footer below the body.</summary>
    [Parameter] public RenderFragment? FooterContent { get; set; }

    /// <summary>Initial width as a CSS pixel value (e.g. <c>"480px"</c>). Defaults to <c>"480px"</c>. Only read once on first open; live size afterward tracks user resizing.</summary>
    [Parameter] public string Width { get; set; } = "480px";

    /// <summary>Initial height as a CSS pixel value. Defaults to <c>"360px"</c>. Only read once on first open; live size afterward tracks user resizing.</summary>
    [Parameter] public string Height { get; set; } = "360px";

    /// <summary>When true (default), shows the bottom-right resize handle and allows dragging it to resize the window.</summary>
    [Parameter] public bool Resizable { get; set; } = true;

    /// <summary>When true (default), the title bar can be dragged to reposition the window.</summary>
    [Parameter] public bool Draggable { get; set; } = true;

    /// <summary>Shows the close button in the title bar. Default is <c>true</c>. Also gates whether Escape closes the window.</summary>
    [Parameter] public bool ShowClose { get; set; } = true;

    /// <summary>Shows the minimize button in the title bar. Default is <c>true</c>.</summary>
    [Parameter] public bool ShowMinimize { get; set; } = true;

    /// <summary>Shows the maximize button in the title bar. Default is <c>true</c>.</summary>
    [Parameter] public bool ShowMaximize { get; set; } = true;

    /// <summary>Initial horizontal position as a CSS pixel value. Defaults to <c>80px</c> when unset. Only read once on first open; clamped to stay within the viewport.</summary>
    [Parameter] public string? InitialX { get; set; }

    /// <summary>Initial vertical position as a CSS pixel value. Defaults to <c>80px</c> when unset. Only read once on first open; clamped to stay within the viewport.</summary>
    [Parameter] public string? InitialY { get; set; }

    /// <summary>Additional CSS classes merged onto the root window element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root window element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _windowId = LumeoIds.New("window");
    private readonly string _titleBarId = LumeoIds.New("window-titlebar");
    private readonly string _titleId = LumeoIds.New("window-title");
    private readonly string _resizeHandleId = LumeoIds.New("window-resize");

    // Shared monotonic z-index counter so the most recently focused/clicked
    // window comes to the front (MDI raise-on-focus). Starts at 40 to match the
    // historical base layer; each raise bumps the shared counter and assigns it
    // to this instance.
    private static int _zCounter = 40;
    private int _zIndex = System.Threading.Interlocked.Increment(ref _zCounter);

    private bool _minimized;
    private bool _maximized;

    // Live visibility state. The window's open-ness is mirrored into _open and
    // rendered from EffectiveOpen so an internal close (Escape / close button)
    // is NOT clobbered by a same-value parent re-render of the Open [Parameter].
    // This is the state-on-data-change guard: live state lives in _open, never
    // in the [Parameter] Open. _lastOpenParam / _hasOpenParam let us reseed _open
    // only when the parent genuinely changes Open. Mirrors the canonical Dialog
    // pattern.
    private bool _open;
    private bool _lastOpenParam;
    private bool _hasOpenParam;
    // CONTROLLED discriminator: the last value we pushed UP via OpenChanged (also
    // re-synced whenever we adopt an authoritative Open). A controlled parent
    // re-render that echoes back this exact value is safe to ignore (keep
    // in-flight state); any other value is an authoritative assertion (veto /
    // normalization / reset) and must win — this is what rolls a vetoed close
    // back to the parent's rejected value instead of leaving the window stuck
    // showing the rejected state forever.
    private bool _lastPushedOpen;

    // Set when the window transitions hidden->visible so OnAfterRenderAsync
    // re-clamps the position/size to the CURRENT viewport on every reopen, not
    // only on first render (a window dragged near an edge then closed must not
    // reopen off-screen after a viewport shrink).
    private bool _needsClamp;

    // Set when the window transitions hidden->visible so OnAfterRenderAsync saves
    // the previously-focused element (the trigger) and moves focus to the dialog
    // root (WCAG 2.4.3 / 3.2.1 focus management). Close() restores focus to the
    // saved element. The save key is the stable per-instance _windowId. Mirrors
    // the non-modal Select/menu pattern (SaveFocus + FocusElement on open,
    // RestoreFocus on close) — Window is non-modal (aria-modal="false") so it must
    // NOT install a Tab focus trap, only move focus inward and restore it.
    private bool _needsFocus;

    private bool EffectiveOpen => _open;

    // Drag state (pointer-events-based; viewport dimensions fetched via JS once per drag start)
    private bool _isDragging;
    private bool _isResizing;
    private long _activePointerId;
    private double _posX;
    private double _posY;
    private double _width;
    private double _height;
    private double _dragStartX;
    private double _dragStartY;
    private double _dragStartPosX;
    private double _dragStartPosY;
    private bool _initialized;

    // Viewport bounds captured at drag-start (and on first render) so the clamp
    // reflects the size at the moment the user grabbed the window rather than
    // a potentially stale value from a previous drag or resize event.
    private double _viewportWidth;
    private double _viewportHeight;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        var hasOpen = parameters.TryGetValue<bool>(nameof(Open), out var incomingOpen);

        // Reseed the live _open from the parent ONLY on a real change (first
        // observation, or an authoritative assertion). A same-value re-render must
        // NOT overwrite an internal close — that is what let an uncontrolled window
        // silently reopen after Escape.
        if (hasOpen)
        {
            if (OpenChanged.HasDelegate)
            {
                // CONTROLLED: the parent owns the value via OpenChanged. Echo of our
                // own push (incomingOpen == _lastPushedOpen) → keep in-flight state
                // (an internal close still pending the parent's re-render). Anything
                // else — veto, normalization, reset, or the very first observation —
                // is an authoritative assertion from the parent and must win. This is
                // what rolls a vetoed close (parent re-renders with Open unchanged)
                // back to the rejected value instead of permanently showing the
                // optimistic state.
                if (!_hasOpenParam || incomingOpen != _lastPushedOpen)
                {
                    // Reopen (false->true): clear any stale minimized/maximized view
                    // so a window that was minimized/maximized when closed comes back
                    // as a normal window, and re-clamp to the live viewport on the
                    // next render.
                    if (incomingOpen && _hasOpenParam && !_lastOpenParam)
                    {
                        _minimized = false;
                        _maximized = false;
                        _needsClamp = true;
                        _needsFocus = true;
                    }
                    _open = incomingOpen;
                    _lastPushedOpen = incomingOpen;
                    _hasOpenParam = true;
                }
            }
            else if (!_hasOpenParam || incomingOpen != _lastOpenParam)
            {
                // UNCONTROLLED: adopt only when the parent genuinely changes the
                // value it supplies, so a same-value re-render must NOT overwrite an
                // internal close.
                if (incomingOpen && _hasOpenParam && !_lastOpenParam)
                {
                    _minimized = false;
                    _maximized = false;
                    _needsClamp = true;
                    _needsFocus = true;
                }
                _open = incomingOpen;
                _lastPushedOpen = incomingOpen;
                _hasOpenParam = true;
            }

            // Keep the uncontrolled discriminator pointing at the last Open we
            // observed, even in controlled mode, so a parent that later unbinds
            // OpenChanged falls back to accurate state-on-data-change tracking.
            _lastOpenParam = incomingOpen;
        }

        return base.SetParametersAsync(parameters);
    }

    protected override void OnParametersSet()
    {
        if (!_initialized && EffectiveOpen)
        {
            _posX = InitialX is not null ? ParsePx(InitialX) : 80;
            _posY = InitialY is not null ? ParsePx(InitialY) : 80;
            _width = ParsePx(Width);
            _height = ParsePx(Height);
            _initialized = true;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Clamp on first render (consumer-provided InitialX/InitialY that exceeds
        // the viewport must be corrected before the user touches the window) AND
        // on every subsequent reopen (_needsClamp), so a window dragged near an
        // edge then closed cannot reopen off-screen after a viewport shrink.
        if ((firstRender || _needsClamp) && EffectiveOpen)
        {
            _needsClamp = false;
            await FetchAndClampToViewportAsync();
            StateHasChanged();
        }

        // Focus management (WCAG 2.4.3): when the window first becomes visible —
        // either rendered open from the start (firstRender) or reopened
        // (false->true, signalled by _needsFocus) — save the element that had
        // focus (the trigger) and move focus to the dialog root so keyboard and
        // screen-reader users land inside the window. The root is tabindex="-1"
        // so it is programmatically focusable. RestoreFocus in Close() hands focus
        // back. No Tab trap is installed (the window is non-modal).
        if ((firstRender || _needsFocus) && EffectiveOpen && !_minimized)
        {
            _needsFocus = false;
            try
            {
                await Interop.SaveFocus(_windowId);
                await Interop.FocusElement(_windowId);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (Microsoft.JSInterop.JSException) { }
            catch (ObjectDisposedException) { }
        }
    }

    private async Task FetchAndClampToViewportAsync()
    {
        try
        {
            var vp = await Interop.GetViewportSize();
            // bUnit's JS layer returns null for unhandled invocations; real
            // browsers always return a populated ViewportSize. Guard so tests
            // (and any future SSR/prerender path) don't NRE.
            if (vp is null) return;
            _viewportWidth = vp.Width;
            _viewportHeight = vp.Height;
            ClampPosition();
        }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (Microsoft.JSInterop.JSException) { }
        catch (ObjectDisposedException) { }
    }

    // Keeps at least MIN_VISIBLE px of the window inside the viewport on all
    // four edges.  The title bar (≈40px) is specifically kept inside the bottom
    // edge so it never slides off and becomes unreachable.
    private const double MinVisible = 50;
    private const double TitleBarHeight = 40;

    private void ClampPosition()
    {
        if (_viewportWidth <= 0 || _viewportHeight <= 0) return;

        // Horizontal: allow the window to go almost completely off the left
        // edge (so only MIN_VISIBLE of it remains visible on the right), but
        // never let the right side go past the right viewport edge minus MIN_VISIBLE.
        _posX = Math.Clamp(_posX, MinVisible - _width, _viewportWidth - MinVisible);

        // Vertical: never let the title bar go above 0 or below the bottom
        // of the viewport (so the close/restore buttons are always reachable).
        _posY = Math.Clamp(_posY, 0, _viewportHeight - TitleBarHeight);
    }

    private static double ParsePx(string value)
    {
        if (string.IsNullOrEmpty(value)) return 0;
        if (value.EndsWith("px", StringComparison.OrdinalIgnoreCase) &&
            double.TryParse(value[..^2], System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out var d))
            return d;
        if (double.TryParse(value, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out var d2))
            return d2;
        return 0;
    }

    // z-index is set inline (not a Tailwind class) so the shared raise-on-focus
    // counter can assign an arbitrary value per window.
    private string ZStyle => $"z-index:{_zIndex.ToString(System.Globalization.CultureInfo.InvariantCulture)};";

    private string StyleString =>
        $"left:{_posX.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;" +
        $"top:{_posY.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;" +
        $"width:{_width.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;" +
        $"height:{_height.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;" +
        ZStyle;

    private string MinimizedStyleString =>
        $"left:{_posX.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;" +
        $"bottom:16px;" +
        ZStyle;

    private string CssClass =>
        Cx.Merge("fixed flex flex-col bg-card border border-border/40 rounded-lg shadow-xl overflow-hidden", Class);

    private async Task HandleTitleBarPointerDown(PointerEventArgs e)
    {
        if (!Draggable) return;
        _isDragging = true;
        _isResizing = false;
        _activePointerId = e.PointerId;
        _dragStartX = e.ClientX;
        _dragStartY = e.ClientY;
        _dragStartPosX = _posX;
        _dragStartPosY = _posY;
        // Capture the pointer on the title bar (same pattern as SplitterDivider):
        // without capture, a fast drag leaves the element, pointermove stops
        // firing and a pointerup outside is lost — _isDragging stayed true and
        // the window glued itself to the cursor on the next hover.
        await Interop.SetPointerCaptureOnElement(_titleBarId, e.PointerId);
        // Fetch current viewport size at drag-start so the clamp in HandlePointerMove
        // always reflects the live viewport (handles viewport resize between drags).
        await FetchAndClampToViewportAsync();
    }

    private async Task HandleResizePointerDown(PointerEventArgs e)
    {
        if (!Resizable) return;
        _isResizing = true;
        _isDragging = false;
        _activePointerId = e.PointerId;
        _dragStartX = e.ClientX;
        _dragStartY = e.ClientY;
        _dragStartPosX = _width;
        _dragStartPosY = _height;
        // Same capture rationale as the title-bar drag above.
        await Interop.SetPointerCaptureOnElement(_resizeHandleId, e.PointerId);
        // Refresh viewport bounds so the resize clamp in HandlePointerMove keeps
        // the window inside the viewport even if it was resized since open.
        await FetchAndClampToViewportAsync();
    }

    private void HandlePointerMove(PointerEventArgs e)
    {
        if (_isDragging)
        {
            var dx = e.ClientX - _dragStartX;
            var dy = e.ClientY - _dragStartY;

            // rc.44 hotfix: clamp ONLY when viewport dimensions are known.
            // Without this guard, `Math.Clamp(value, 0, -40)` throws when the
            // viewport fetch hasn't completed yet (or returned null in tests/SSR).
            // Mirror the ClampPosition() guard so drag-during-init doesn't crash.
            //
            // Clamp meaning when valid:
            //   X: allow almost-fully-left (right edge stays visible) but not past right edge.
            //   Y: never above 0 (title bar stays in viewport top) and never below
            //      (viewport height − title bar height) so the controls are always reachable.
            if (_viewportWidth > 0 && _viewportHeight > TitleBarHeight)
            {
                _posX = Math.Clamp(_dragStartPosX + dx, MinVisible - _width, _viewportWidth - MinVisible);
                _posY = Math.Clamp(_dragStartPosY + dy, 0, _viewportHeight - TitleBarHeight);
            }
            else
            {
                // Pre-viewport-fetch fallback: lower-bound only (matches pre-rc.44 behavior).
                _posX = Math.Max(0, _dragStartPosX + dx);
                _posY = Math.Max(0, _dragStartPosY + dy);
            }
            StateHasChanged();
        }
        else if (_isResizing)
        {
            var dx = e.ClientX - _dragStartX;
            var dy = e.ClientY - _dragStartY;
            var width = Math.Max(200, _dragStartPosX + dx);
            var height = Math.Max(120, _dragStartPosY + dy);

            // Re-clamp against the viewport so a window near an edge can't grow
            // off-screen (drag is already clamped; resize previously only had a
            // lower bound). Keep an 8px breathing margin on the far edges.
            if (_viewportWidth > 0)
            {
                var maxWidth = _viewportWidth - _posX - 8;
                if (maxWidth >= 200) width = Math.Min(width, maxWidth);
            }
            if (_viewportHeight > 0)
            {
                var maxHeight = _viewportHeight - _posY - 8;
                if (maxHeight >= 120) height = Math.Min(height, maxHeight);
            }

            _width = width;
            _height = height;
            StateHasChanged();
        }
    }

    private async Task HandlePointerUp(PointerEventArgs e)
    {
        if (_isDragging)
        {
            await Interop.ReleasePointerCaptureOnElement(_titleBarId, _activePointerId);
        }
        else if (_isResizing)
        {
            await Interop.ReleasePointerCaptureOnElement(_resizeHandleId, _activePointerId);
        }
        _isDragging = false;
        _isResizing = false;
    }

    private void ToggleMinimize()
    {
        _minimized = !_minimized;
        if (_minimized) _maximized = false;
    }

    private void ToggleMaximize()
    {
        _maximized = !_maximized;
        if (_maximized) _minimized = false;
    }

    // Raise-on-focus: assign the next shared z-index so a click anywhere on a
    // background window brings it to the front (the defining MDI behaviour).
    // Cheap no-op when this window is already the topmost.
    private void BringToFront()
    {
        if (_zIndex == _zCounter) return;
        _zIndex = System.Threading.Interlocked.Increment(ref _zCounter);
        StateHasChanged();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && ShowClose)
        {
            await Close();
        }
    }

    private async Task Close()
    {
        // Update the live backing field only — NEVER the [Parameter] Open.
        // OpenChanged notifies two-way @bind-Open / controlled consumers; _open
        // carries the live close so an uncontrolled window (no OpenChanged) and a
        // one-way controlled parent both observe the close until the parent
        // chooses to re-assert Open. Reset the transient view mode so the window
        // does not reopen stuck in its minimized/maximized state.
        _minimized = false;
        _maximized = false;
        _open = false;
        // Record _lastPushedOpen BEFORE invoking OpenChanged: a controlled parent
        // re-renders synchronously inside InvokeAsync, so SetParametersAsync must
        // already see this value as "the value we just pushed" to distinguish an
        // accepted echo (keep in-flight state) from a veto (parent kept its old
        // value → roll back to it).
        _lastPushedOpen = false;
        await OpenChanged.InvokeAsync(false);
        // Return focus to the element that was focused when the window opened (WCAG 2.4.3) — typically
        // the trigger that launched it. Saved under the stable per-instance _windowId key in
        // OnAfterRenderAsync on open. Done AFTER (not before) the InvokeAsync above, and only when the
        // close was actually accepted: a controlled parent can veto the close by re-rendering with
        // Open=true — SetParametersAsync rolls _open back to true SYNCHRONOUSLY inside InvokeAsync (see
        // its comment), so checking _open here reliably detects the veto. Restoring focus unconditionally
        // would move keyboard focus away from a window that is still visible (Codex P2).
        if (!_open)
        {
            try
            {
                await Interop.RestoreFocus(_windowId);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (Microsoft.JSInterop.JSException) { }
            catch (ObjectDisposedException) { }
        }
        // Re-render so an uncontrolled window (no OpenChanged delegate) actually
        // hides — without this it would never re-render and so never close.
        StateHasChanged();
    }

    public ValueTask DisposeAsync() => ValueTask.CompletedTask;
}
